import React from 'react';
import ReactDOM from 'react-dom';
import './index.css';
function main () {
    return (
        <div classname = "main">
            <head>
                <title>React Test</title>
            </head>
            <body>
                <div id = "react-dom">
                    <HelloWorld/>
                </div>
            </body>
        </div>
    )
}
function name (){
    return "Amruth Nadimpally"
}
class HelloWorld extends React.Component {
    render(){
        return <h2>Hello {props.name}!</h2>
    }
}
